  return <MenuItem {...props} ref={listItemRef} tabIndex={0} />;
}

function TrackRenderCountMenuItem({ actions, ...other }) {
  const renderCountRef = React.useRef(0);
  React.useEffect(() => {
    renderCountRef.current += 1;
